import android.util.Log;
import okhttp3.Interceptor;
import okhttp3.Request;
import okhttp3.RequestBody;
import okhttp3.Response;
import okhttp3.ResponseBody;
import okio.Buffer;
import org.json.JSONObject;
import org.json.JSONArray;
import java.io.IOException;
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;

public class SecureNetworkLogger implements Interceptor {
    private static final String TAG = "NetworkDebug";
    private final boolean isDebugBuild;
    
    private static final Set<String> SENSITIVE_HEADERS = new HashSet<>(Arrays.asList(
        "authorization", "x-auth-token", "x-api-key", "cookie", "set-cookie",
        "x-access-token", "x-refresh-token", "api-key", "apikey", "auth-token"
    ));
    
    private static final Set<String> SENSITIVE_FIELDS = new HashSet<>(Arrays.asList(
        "password", "passwd", "pwd", "secret", "token", "access_token", 
        "refresh_token", "api_key", "apikey", "auth_token", "authorization",
        "credit_card", "creditcard", "cvv", "ssn", "social_security",
        "pin", "private_key", "privatekey", "session_id", "sessionid"
    ));

    public SecureNetworkLogger(boolean isDebugBuild) {
        this.isDebugBuild = isDebugBuild;
    }

    @Override
    public Response intercept(Chain chain) throws IOException {
        Request request = chain.getRequest();
        
        if (isDebugBuild) {
            logRequestVerbose(request);
        } else {
            logRequestProduction(request);
        }
        
        long startTime = System.currentTimeMillis();
        Response response;
        
        try {
            response = chain.proceed(request);
        } catch (Exception e) {
            logError(request, e);
            throw e;
        }
        
        long duration = System.currentTimeMillis() - startTime;
        
        if (isDebugBuild) {
            response = logResponseVerbose(response, duration);
        } else {
            logResponseProduction(response, duration);
        }
        
        return response;
    }

    private void logRequestProduction(Request request) {
        Log.i(TAG, String.format("→ %s %s", request.method(), sanitizeUrl(request.url().toString())));
        Log.i(TAG, "Headers: " + getSafeHeaderCount(request));
    }

    private void logRequestVerbose(Request request) {
        Log.d(TAG, "╔═══════════════════════════════════════════════════════════");
        Log.d(TAG, "║ REQUEST");
        Log.d(TAG, "╠═══════════════════════════════════════════════════════════");
        Log.d(TAG, "║ Method: " + request.method());
        Log.d(TAG, "║ URL: " + sanitizeUrl(request.url().toString()));
        
        logHeaders(request);
        
        if (request.body() != null) {
            logRequestBody(request);
        }
        
        Log.d(TAG, "╚═══════════════════════════════════════════════════════════");
    }

    private void logHeaders(Request request) {
        Log.d(TAG, "║ Headers:");
        request.headers().names().forEach(name -> {
            String value = request.header(name);
            if (isSensitiveHeader(name)) {
                Log.d(TAG, "║   " + name + ": [REDACTED]");
            } else {
                Log.d(TAG, "║   " + name + ": " + value);
            }
        });
    }

    private void logRequestBody(Request request) {
        try {
            RequestBody body = request.body();
            if (body == null) return;
            
            String contentType = body.contentType() != null ? body.contentType().toString() : "unknown";
            Log.d(TAG, "║ Content-Type: " + contentType);
            
            if (isLoggableContentType(contentType)) {
                Buffer buffer = new Buffer();
                body.writeTo(buffer);
                String bodyString = buffer.readUtf8();
                
                String sanitized = sanitizeBody(bodyString, contentType);
                Log.d(TAG, "║ Body: " + sanitized);
            } else {
                Log.d(TAG, "║ Body: [Binary data - " + body.contentLength() + " bytes]");
            }
        } catch (Exception e) {
            Log.d(TAG, "║ Body: [Error reading body]");
        }
    }

    private void logResponseProduction(Response response, long duration) {
        Log.i(TAG, String.format("← %d %s (%dms)", 
            response.code(), 
            sanitizeUrl(response.request().url().toString()),
            duration));
    }

    private Response logResponseVerbose(Response response, long duration) throws IOException {
        Log.d(TAG, "╔═══════════════════════════════════════════════════════════");
        Log.d(TAG, "║ RESPONSE");
        Log.d(TAG, "╠═══════════════════════════════════════════════════════════");
        Log.d(TAG, "║ URL: " + sanitizeUrl(response.request().url().toString()));
        Log.d(TAG, "║ Status: " + response.code() + " " + response.message());
        Log.d(TAG, "║ Duration: " + duration + "ms");
        
        logResponseHeaders(response);
        
        ResponseBody responseBody = response.body();
        if (responseBody != null) {
            String contentType = responseBody.contentType() != null ? 
                responseBody.contentType().toString() : "unknown";
            
            if (isLoggableContentType(contentType)) {
                String bodyString = responseBody.string();
                String sanitized = sanitizeBody(bodyString, contentType);
                Log.d(TAG, "║ Body: " + sanitized);
                
                ResponseBody newBody = ResponseBody.create(responseBody.contentType(), bodyString);
                response = response.newBuilder().body(newBody).build();
            } else {
                Log.d(TAG, "║ Body: [Binary data - " + responseBody.contentLength() + " bytes]");
            }
        }
        
        Log.d(TAG, "╚═══════════════════════════════════════════════════════════");
        return response;
    }

    private void logResponseHeaders(Response response) {
        Log.d(TAG, "║ Headers:");
        response.headers().names().forEach(name -> {
            String value = response.header(name);
            if (isSensitiveHeader(name)) {
                Log.d(TAG, "║   " + name + ": [REDACTED]");
            } else {
                Log.d(TAG, "║   " + name + ": " + value);
            }
        });
    }

    private void logError(Request request, Exception e) {
        if (isDebugBuild) {
            Log.d(TAG, "╔═══════════════════════════════════════════════════════════");
            Log.d(TAG, "║ REQUEST FAILED");
            Log.d(TAG, "╠═══════════════════════════════════════════════════════════");
            Log.d(TAG, "║ URL: " + sanitizeUrl(request.url().toString()));
            Log.d(TAG, "║ Error: " + e.getClass().getSimpleName());
            Log.d(TAG, "║ Message: " + e.getMessage());
            Log.d(TAG, "╚═══════════════════════════════════════════════════════════");
        } else {
            Log.i(TAG, String.format("✗ Request failed: %s - %s", 
                sanitizeUrl(request.url().toString()), 
                e.getClass().getSimpleName()));
        }
    }

    private String sanitizeUrl(String url) {
        if (url.contains("?")) {
            String[] parts = url.split("\\?", 2);
            String queryString = parts[1];
            
            String[] params = queryString.split("&");
            StringBuilder sanitized = new StringBuilder();
            
            for (String param : params) {
                String[] keyValue = param.split("=", 2);
                if (keyValue.length == 2) {
                    String key = keyValue[0].toLowerCase();
                    if (isSensitiveField(key)) {
                        sanitized.append(keyValue[0]).append("=[REDACTED]&");
                    } else {
                        sanitized.append(param).append("&");
                    }
                } else {
                    sanitized.append(param).append("&");
                }
            }
            
            if (sanitized.length() > 0) {
                sanitized.setLength(sanitized.length() - 1);
            }
            
            return parts[0] + "?" + sanitized.toString();
        }
        return url;
    }

    private String sanitizeBody(String body, String contentType) {
        if (body == null || body.isEmpty()) {
            return "[Empty]";
        }
        
        if (body.length() > 10000) {
            body = body.substring(0, 10000) + "... [Truncated]";
        }
        
        if (contentType.contains("json")) {
            return sanitizeJson(body);
        }
        
        return sanitizeGenericBody(body);
    }

    private String sanitizeJson(String json) {
        try {
            if (json.trim().startsWith("{")) {
                JSONObject obj = new JSONObject(json);
                return sanitizeJsonObject(obj).toString(2);
            } else if (json.trim().startsWith("[")) {
                JSONArray arr = new JSONArray(json);
                return sanitizeJsonArray(arr).toString(2);
            }
        } catch (Exception e) {
            return sanitizeGenericBody(json);
        }
        return json;
    }

    private JSONObject sanitizeJsonObject(JSONObject obj) {
        JSONObject sanitized = new JSONObject();
        try {
            for (String key : obj.keySet()) {
                Object value = obj.get(key);
                if (isSensitiveField(key)) {
                    sanitized.put(key, "[REDACTED]");
                } else if (value instanceof JSONObject) {
                    sanitized.put(key, sanitizeJsonObject((JSONObject) value));
                } else if (value instanceof JSONArray) {
                    sanitized.put(key, sanitizeJsonArray((JSONArray) value));
                } else {
                    sanitized.put(key, value);
                }
            }
        } catch (Exception e) {
            return obj;
        }
        return sanitized;
    }

    private JSONArray sanitizeJsonArray(JSONArray arr) {
        JSONArray sanitized = new JSONArray();
        try {
            for (int i = 0; i < arr.length(); i++) {
                Object value = arr.get(i);
                if (value instanceof JSONObject) {
                    sanitized.put(sanitizeJsonObject((JSONObject) value));
                } else if (value instanceof JSONArray) {
                    sanitized.put(sanitizeJsonArray((JSONArray) value));
                } else {
                    sanitized.put(value);
                }
            }
        } catch (Exception e) {
            return arr;
        }
        return sanitized;
    }

    private String sanitizeGenericBody(String body) {
        String sanitized = body;
        for (String field : SENSITIVE_FIELDS) {
            sanitized = sanitized.replaceAll(
                "(?i)([\"']?" + field + "[\"']?\\s*[:=]\\s*[\"']?)[^\"'&\\s]+",
                "$1[REDACTED]"
            );
        }
        return sanitized;
    }

    private boolean isSensitiveHeader(String headerName) {
        return SENSITIVE_HEADERS.contains(headerName.toLowerCase());
    }

    private boolean isSensitiveField(String fieldName) {
        String lower = fieldName.toLowerCase();
        for (String sensitive : SENSITIVE_FIELDS) {
            if (lower.contains(sensitive)) {
                return true;
            }
        }
        return false;
    }

    private boolean isLoggableContentType(String contentType) {
        return contentType.contains("json") || 
               contentType.contains("xml") || 
               contentType.contains("text") ||
               contentType.contains("x-www-form-urlencoded");
    }

    private int getSafeHeaderCount(Request request) {
        return request.headers().size();
    }
}